20: type Dialect interface {
21: 	DriverName() string
22: 	Quote(string) string
23: 	AndStr() string
24: 	AutoIncrStr() string
25: 	OrStr() string
26: 	EqStr() string
27: 	ShowCreateNull() bool
28: 	SQLType(col *Column) string
29: 	SupportEngine() bool
30: 	// LikeOperator returns SQL snippet and query parameter for case-insensitive LIKE operation, with optional wildcards (%) before/after the pattern.
31: 	LikeOperator(column string, wildcardBefore bool, pattern string, wildcardAfter bool) (string, string)
32: 	Default(col *Column) string
33: 	// BooleanValue can be used as an argument in SELECT or INSERT statements. For constructing
34: 	// raw SQL queries, please use BooleanStr instead.
35: 	BooleanValue(bool) any
36: 	// BooleanStr should only be used to construct SQL statements (strings). For arguments to queries, use BooleanValue instead.
37: 	BooleanStr(bool) string
38: 	DateTimeFunc(string) string
39: 	BatchSize() int
40: 	UnionDistinct() string // this is the default UNION type
41: 	UnionAll() string
42: 
43: 	OrderBy(order string) string
44: 
45: 	CreateIndexSQL(tableName string, index *Index) string
46: 	CreateTableSQL(table *Table) string
47: 	AddColumnSQL(tableName string, col *Column) string
48: 	CopyTableData(sourceTable string, targetTable string, sourceCols []string, targetCols []string) string
49: 	DropTable(tableName string) string
50: 	DropIndexSQL(tableName string, index *Index) string
51: 
52: 	// RenameTable is deprecated, its use cause breaking changes
53: 	// so, it should no longer be used. Kept for legacy reasons.
54: 	RenameTable(oldName string, newName string) string
55: 	// RenameColumn is deprecated, its use cause breaking changes
56: 	// so, it should no longer be used. Kept for legacy reasons.
57: 	RenameColumn(table Table, column *Column, newName string) string
58: 
59: 	UpdateTableSQL(tableName string, columns []*Column) string
60: 
61: 	IndexCheckSQL(tableName, indexName string) (string, []any)
62: 	ColumnCheckSQL(tableName, columnName string) (string, []any)
63: 	// UpsertSQL returns the upsert sql statement for a dialect
64: 	UpsertSQL(tableName string, keyCols, updateCols []string) string
65: 	UpsertMultipleSQL(tableName string, keyCols, updateCols []string, count int) (string, error)
66: 
67: 	ColString(*Column) string
68: 	ColStringNoPk(*Column) string
69: 
70: 	Limit(limit int64) string
71: 	LimitOffset(limit int64, offset int64) string
72: 
73: 	PreInsertId(table string, sess *xorm.Session) error
74: 	PostInsertId(table string, sess *xorm.Session) error
75: 
76: 	CleanDB(engine *xorm.Engine) error
77: 	TruncateDBTables(engine *xorm.Engine) error
78: 	// CreateDatabaseFromSnapshot is called when migration log table is not found.
79: 	// Dialect can recreate all tables from existing snapshot. After successful (nil error) return,
80: 	// migrator will list migrations from the log, and apply all missing migrations.
81: 	CreateDatabaseFromSnapshot(ctx context.Context, engine *xorm.Engine, migrationLogTableName string, logger log.Logger) error
82: 
83: 	IsUniqueConstraintViolation(err error) bool
84: 	ErrorMessage(err error) string
85: 	IsDeadlock(err error) bool
86: 	Lock(LockCfg) error
87: 	Unlock(LockCfg) error
88: 
89: 	GetDBName(string) (string, error)
90: 
91: 	// InsertQuery accepts a table name and a map of column names to values to insert.
92: 	// It returns a query string and a slice of parameters that can be executed against the database.
93: 	InsertQuery(tableName string, row map[string]any) (string, []any, error)
94: 	// UpdateQuery accepts a table name, a map of column names to values to update, and a map of
95: 	// column names to values to use in the where clause.
96: 	// It returns a query string and a slice of parameters that can be executed against the database.
97: 	UpdateQuery(tableName string, row map[string]any, where map[string]any) (string, []any, error)
98: 	// Insert accepts a table name and a map of column names to insert.
99: 	// The insert is executed as part of the provided session.
100: 	Insert(ctx context.Context, tx *session.SessionTx, tableName string, row map[string]any) error
101: 	// Update accepts a table name, a map of column names to values to update, and a map of
102: 	// column names to values to use in the where clause.
103: 	// The update is executed as part of the provided session.
104: 	Update(ctx context.Context, tx *session.SessionTx, tableName string, row map[string]any, where map[string]any) error
105: 	// Concat returns the sql statement for concating multiple strings
106: 	// Implementations are not expected to quote the arguments
107: 	// therefore any callers should take care to quote arguments as necessary
108: 	Concat(...string) string
109: }
