117: type dialectFunc func() Dialect
118: 
119: var supportedDialects = map[string]dialectFunc{
120: 	MySQL:                  NewMysqlDialect,
121: 	SQLite:                 NewSQLite3Dialect,
122: 	Postgres:               NewPostgresDialect,
123: 	MySQL + "WithHooks":    NewMysqlDialect,
124: 	SQLite + "WithHooks":   NewSQLite3Dialect,
125: 	Postgres + "WithHooks": NewPostgresDialect,
126: }
127: 
128: func NewDialect(driverName string) Dialect {
129: 	if fn, exist := supportedDialects[driverName]; exist {
130: 		return fn()
131: 	}
132: 
133: 	panic("Unsupported database type: " + driverName)
134: }
