136: type BaseDialect struct {
137: 	dialect    Dialect
138: 	driverName string
139: }
140: 
141: func (b *BaseDialect) DriverName() string {
142: 	return b.driverName
143: }
144: 
145: func (b *BaseDialect) ShowCreateNull() bool {
146: 	return true
147: }
