153: func (b *BaseDialect) LikeOperator(column string, wildcardBefore bool, pattern string, wildcardAfter bool) (string, string) {
154: 	param := pattern
155: 	if wildcardBefore {
156: 		param = "%" + param
157: 	}
158: 	if wildcardAfter {
159: 		param = param + "%"
160: 	}
161: 	return fmt.Sprintf("%s LIKE ?", column), param
162: }
