172: func (b *BaseDialect) Default(col *Column) string {
173: 	if col.Type == DB_Bool {
174: 		// Ensure that all dialects support the same literals in the same way.
175: 		bl, err := strconv.ParseBool(col.Default)
176: 		if err != nil {
177: 			panic(fmt.Errorf("failed to create default value for column '%s': invalid boolean default value '%s'", col.Name, col.Default))
178: 		}
179: 		return b.dialect.BooleanStr(bl)
180: 	}
181: 	return col.Default
182: }
