188: func (b *BaseDialect) CreateTableSQL(table *Table) string {
189: 	sql := "CREATE TABLE IF NOT EXISTS "
190: 	sql += b.dialect.Quote(table.Name) + " (\n"
191: 
192: 	pkList := table.PrimaryKeys
193: 
194: 	for _, col := range table.Columns {
195: 		if col.IsPrimaryKey && len(pkList) == 1 {
196: 			sql += col.String(b.dialect)
197: 		} else {
198: 			sql += col.StringNoPk(b.dialect)
199: 		}
200: 		sql = strings.TrimSpace(sql)
201: 		sql += "\n, "
202: 	}
203: 
204: 	if len(pkList) > 1 {
205: 		quotedCols := make([]string, 0, len(pkList))
206: 		for _, col := range pkList {
207: 			quotedCols = append(quotedCols, b.dialect.Quote(col))
208: 		}
209: 
210: 		sql += "PRIMARY KEY ( " + strings.Join(quotedCols, ",") + " ), "
211: 	}
212: 
213: 	sql = sql[:len(sql)-2] + ")"
214: 	if b.dialect.SupportEngine() {
215: 		sql += " ENGINE=InnoDB DEFAULT CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci"
216: 	}
217: 
218: 	sql += ";"
219: 	return sql
220: }
221: 
222: func (b *BaseDialect) AddColumnSQL(tableName string, col *Column) string {
223: 	return fmt.Sprintf("alter table %s ADD COLUMN %s", b.dialect.Quote(tableName), col.StringNoPk(b.dialect))
224: }
225: 
226: func (b *BaseDialect) CreateIndexSQL(tableName string, index *Index) string {
227: 	quote := b.dialect.Quote
228: 	var unique string
229: 	if index.Type == UniqueIndex {
230: 		unique = " UNIQUE"
231: 	}
232: 
233: 	idxName := index.XName(tableName)
234: 
235: 	quotedCols := make([]string, 0, len(index.Cols))
236: 	for _, col := range index.Cols {
237: 		quotedCols = append(quotedCols, b.dialect.Quote(col))
238: 	}
239: 
240: 	return fmt.Sprintf("CREATE%s INDEX %v ON %v (%v);", unique, quote(idxName), quote(tableName), strings.Join(quotedCols, ","))
241: }
242: 
243: func (b *BaseDialect) QuoteColList(cols []string) string {
244: 	var sourceColsSQL = ""
245: 	for _, col := range cols {
246: 		sourceColsSQL += b.dialect.Quote(col)
247: 		sourceColsSQL += "\n, "
248: 	}
249: 	return strings.TrimSuffix(sourceColsSQL, "\n, ")
250: }
251: 
252: func (b *BaseDialect) CopyTableData(sourceTable string, targetTable string, sourceCols []string, targetCols []string) string {
253: 	sourceColsSQL := b.QuoteColList(sourceCols)
254: 	targetColsSQL := b.QuoteColList(targetCols)
255: 
256: 	quote := b.dialect.Quote
257: 	return fmt.Sprintf("INSERT INTO %s (%s)\nSELECT %s\nFROM %s", quote(targetTable), targetColsSQL, sourceColsSQL, quote(sourceTable))
258: }
