292: func (b *BaseDialect) ColString(col *Column) string {
293: 	sql := b.dialect.Quote(col.Name) + " "
294: 
295: 	sql += b.dialect.SQLType(col) + " "
296: 
297: 	if col.IsPrimaryKey {
298: 		sql += "PRIMARY KEY "
299: 		if col.IsAutoIncrement {
300: 			sql += b.dialect.AutoIncrStr() + " "
301: 		}
302: 	}
303: 
304: 	if b.dialect.ShowCreateNull() {
305: 		if col.Nullable {
306: 			sql += "NULL "
307: 		} else {
308: 			sql += "NOT NULL "
309: 		}
310: 	}
311: 
312: 	if col.Default != "" {
313: 		sql += "DEFAULT " + b.dialect.Default(col) + " "
314: 	}
315: 
316: 	return sql
317: }
318: 
319: func (b *BaseDialect) ColStringNoPk(col *Column) string {
320: 	sql := b.dialect.Quote(col.Name) + " "
321: 
322: 	sql += b.dialect.SQLType(col) + " "
323: 
324: 	if b.dialect.ShowCreateNull() {
325: 		if col.Nullable {
326: 			sql += "NULL "
327: 		} else {
328: 			sql += "NOT NULL "
329: 		}
330: 	}
331: 
332: 	if col.Default != "" {
333: 		sql += "DEFAULT " + b.dialect.Default(col) + " "
334: 	}
335: 
336: 	return sql
337: }
