388: func (b *BaseDialect) InsertQuery(tableName string, row map[string]any) (string, []any, error) {
389: 	if len(row) < 1 {
390: 		return "", nil, fmt.Errorf("no columns provided")
391: 	}
392: 
393: 	// allocate slices
394: 	cols := make([]string, 0, len(row))
395: 	vals := make([]any, 0, len(row))
396: 	keys := make([]string, 0, len(row))
397: 
398: 	// create sorted list of columns
399: 	for col := range row {
400: 		keys = append(keys, col)
401: 	}
402: 	slices.Sort(keys)
403: 
404: 	// build query and values
405: 	for _, col := range keys {
406: 		cols = append(cols, b.dialect.Quote(col))
407: 		vals = append(vals, row[col])
408: 	}
409: 
410: 	return fmt.Sprintf("INSERT INTO %s (%s) VALUES (%s)", b.dialect.Quote(tableName), strings.Join(cols, ", "), strings.Repeat("?, ", len(row)-1)+"?"), vals, nil
411: }
412: 
413: func (b *BaseDialect) UpdateQuery(tableName string, row map[string]any, where map[string]any) (string, []any, error) {
414: 	if len(row) < 1 {
415: 		return "", nil, fmt.Errorf("no columns provided")
416: 	}
417: 
418: 	if len(where) < 1 {
419: 		return "", nil, fmt.Errorf("no where clause provided")
420: 	}
421: 
422: 	// allocate slices
423: 	cols := make([]string, 0, len(row))
424: 	whereCols := make([]string, 0, len(where))
425: 	vals := make([]any, 0, len(row)+len(where))
426: 	keys := make([]string, 0, len(row))
427: 
428: 	// create sorted list of columns to update
429: 	for col := range row {
430: 		keys = append(keys, col)
431: 	}
432: 	slices.Sort(keys)
433: 
434: 	// build update query and values
435: 	for _, col := range keys {
436: 		cols = append(cols, b.dialect.Quote(col)+"=?")
437: 		vals = append(vals, row[col])
438: 	}
439: 
440: 	// create sorted list of columns for where clause
441: 	keys = make([]string, 0, len(where))
442: 	for col := range where {
443: 		keys = append(keys, col)
444: 	}
445: 	slices.Sort(keys)
446: 
447: 	// build where clause and values
448: 	for _, col := range keys {
449: 		whereCols = append(whereCols, b.dialect.Quote(col)+"=?")
450: 		vals = append(vals, where[col])
451: 	}
452: 
453: 	return fmt.Sprintf("UPDATE %s SET %s WHERE %s", b.dialect.Quote(tableName), strings.Join(cols, ", "), strings.Join(whereCols, " AND ")), vals, nil
454: }
455: 
456: func (b *BaseDialect) Insert(ctx context.Context, tx *session.SessionTx, tableName string, row map[string]any) error {
457: 	query, args, err := b.InsertQuery(tableName, row)
458: 	if err != nil {
459: 		return err
460: 	}
461: 
462: 	_, err = tx.Exec(ctx, query, args...)
463: 	return err
464: }
465: 
466: func (b *BaseDialect) Update(ctx context.Context, tx *session.SessionTx, tableName string, row map[string]any, where map[string]any) error {
467: 	query, args, err := b.UpdateQuery(tableName, row, where)
468: 	if err != nil {
469: 		return err
470: 	}
471: 
472: 	_, err = tx.Exec(ctx, query, args...)
473: 	return err
474: }
475: 
476: func (b *BaseDialect) Concat(strs ...string) string {
477: 	return fmt.Sprintf("CONCAT(%s)", strings.Join(strs, ", "))
478: }
479: 
480: func (b *BaseDialect) UnionDistinct() string {
481: 	return "UNION"
482: }
483: 
484: func (b *BaseDialect) UnionAll() string {
485: 	return "UNION ALL"
486: }
